Rules.InvariantScript:
Set(
    varGPSCaptured,
    !IsBlank(Location.Latitude) && !IsBlank(Location.Longitude)
);

Set(
    varLocationText,
    If(
        varGPSCaptured,
        Text(Location.Latitude, "[$-en-US]0.000000") & ", " & Text(Location.Longitude, "[$-en-US]0.000000"),
        "Location not captured. Please enable location services."
    )
)

Set(
    varGPSCaptured,
    !IsBlank(Location.Latitude) && !IsBlank(Location.Longitude)
);

Set(
    varIncidentLocation,
    If(
        varGPSCaptured,
        Text(Location.Latitude, "[$-en-US]0.000000") & ", " & Text(Location.Longitude, "[$-en-US]0.000000"),
        "Location not captured"
    )
);

Set(
    varIncidentID,
    "INC-" & Text(Now(), "yyyymmddhhmmss")
);

IfError(
    Set(
        varSelectedIncident,
        Patch(
            EmergencyIncidents,
            Defaults(EmergencyIncidents),
            {
                Title: varIncidentID,
                'Incident ID': varIncidentID,
                Location: varIncidentLocation,
                'Reporter Email': User().Email,
                Status: {Value: "New"},
                'Created Time': Now(),
                'Last Updated': Now(),
                'GPS Status': {Value: If(varGPSCaptured, "Captured", "Not Captured")},
                'Reports From Same Reporter': CountRows(
                    Filter(
                        EmergencyIncidents,
                        'Reporter Email' = User().Email
                    )
                ) + 1,
                'Incident Type': {Value: ddlIncidentType.Selected.Value},
                'Support Requested': false
            }
        )
    );

    Refresh(EmergencyIncidents);

    Navigate(EmergencyStatusScreen, ScreenTransition.Fade),

    Notify(
        "Incident was not saved: " & FirstError.Message,
        NotificationType.Error
    )
)
